# Minimal iOS Habit Tracking App

Below is a minimal working version of a native iOS habit tracking application using SwiftUI. This implementation includes basic functionality to add habits, mark them as completed for the current date, and view completion history.

## ContentView.swift

```swift
import SwiftUI

// Data model for a habit
struct Habit: Identifiable, Codable {
    let id = UUID()
    let name: String
    var completionDates: [String] // Array of date strings in "YYYY-MM-DD" format

    init(name: String) {
        self.name = name
        self.completionDates = []
    }

    // Check if habit is completed for today
    func isCompletedToday() -> Bool {
        let today = Date()
        let dateFormatter = DateFormatter()
        dateFormatter.dateFormat = "yyyy-MM-dd"
        let todayString = dateFormatter.string(from: today)
        return completionDates.contains(todayString)
    }
}

// Main app view
struct ContentView: View {
    @State private var habits: [Habit] = []
    @State private var showingAddHabit = false
    @State private var newHabitName = ""

    // Load saved data
    private func loadHabits() {
        let defaults = UserDefaults.standard
        if let data = defaults.data(forKey: "habits"),
           let decoded = try? JSONDecoder().decode([Habit].self, from: data) {
            habits = decoded
        }
    }

    // Save data
    private func saveHabits() {
        if let encoded = try? JSONEncoder().encode(habits) {
            UserDefaults.standard.set(encoded, forKey: "habits")
        }
    }

    // Add a new habit
    private func addHabit() {
        guard !newHabitName.trimmingCharacters(in: .whitespaces).isEmpty else { return }
        let habit = Habit(name: newHabitName)
        habits.append(habit)
        newHabitName = ""
        showingAddHabit = false
        saveHabits()
    }

    // Toggle habit completion for today
    private func toggleHabitCompletion(_ habit: Habit) {
        let today = Date()
        let dateFormatter = DateFormatter()
        dateFormatter.dateFormat = "yyyy-MM-dd"
        let todayString = dateFormatter.string(from: today)

        if let index = habits.firstIndex(where: { $0.id == habit.id }) {
            if habit.completionDates.contains(todayString) {
                // Remove today's completion
                habits[index].completionDates = habits[index].completionDates.filter { $0 != todayString }
            } else {
                // Add today's completion
                habits[index].completionDates.append(todayString)
            }
            saveHabits()
        }
    }

    // Delete a habit
    private func deleteHabit(at offsets: IndexSet) {
        habits.remove(atOffsets: offsets)
        saveHabits()
    }

    var body: some View {
        NavigationView {
            List {
                ForEach(habits) { habit in
                    HStack {
                        Text(habit.name)
                            .font(.headline)

                        Spacer()

                        // Completion button
                        Button {
                            toggleHabitCompletion(habit)
                        } label: {
                            Image(systemName: habit.isCompletedToday() ? "checkmark.circle.fill" : "circle")
                                .foregroundColor(habit.isCompletedToday() ? .green : .gray)
                        }
                        .buttonStyle(PlainButtonStyle())
                    }
                    .padding(.vertical, 4)
                }
                .onDelete(perform: deleteHabit)
            }
            .navigationTitle("Habit Tracker")
            .toolbar {
                ToolbarItem(placement: .navigationBarTrailing) {
                    Button {
                        showingAddHabit = true
                    } label: {
                        Image(systemName: "plus")
                    }
                }
            }
            .sheet(isPresented: $showingAddHabit) {
                NavigationView {
                    VStack {
                        TextField("Enter habit name", text: $newHabitName)
                            .textFieldStyle(RoundedBorderTextFieldStyle())
                            .padding()

                        Button("Add Habit") {
                            addHabit()
                        }
                        .font(.headline)
                        .frame(maxWidth: .infinity)
                        .padding()
                        .background(Color.blue)
                        .foregroundColor(.white)
                        .cornerRadius(10)
                        .padding(.horizontal)
                    }
                    .navigationTitle("New Habit")
                    .navigationBarTitleDisplayMode(.inline)
                    .toolbar {
                        ToolbarItem(placement: .cancellationAction) {
                            Button("Cancel") {
                                showingAddHabit = false
                                newHabitName = ""
                            }
                        }
                    }
                }
            }
            .onAppear {
                loadHabits()
            }
            .overlay(
                // Empty state
                Group {
                    if habits.isEmpty {
                        VStack {
                            Image(systemName: "checkmark.seal")
                                .font(.system(size: 60))
                                .foregroundColor(.gray)
                                .padding()

                            Text("No habits yet")
                                .font(.headline)
                                .foregroundColor(.gray)

                            Text("Tap the + button to add your first habit")
                                .font(.caption)
                                .foregroundColor(.gray)
                                .multilineTextAlignment(.center)
                                .padding(.horizontal)
                        }
                    }
                }
            )
        }
    }
}

struct ContentView_Previews: PreviewProvider {
    static var previews: some View {
        ContentView()
    }
}
```

## HabitTrackerApp.swift

```swift
