@main
struct HabitTrackerApp: App {
    var body: some Scene {
        WindowGroup {
            ContentView()
        }
    }
}
```

## Features

1. **Add Habits**: Users can add new habits with custom names
2. **Track Completion**: Toggle completion status for each habit on the current day
3. **Persistence**: Data is saved using UserDefaults
4. **Delete Habits**: Swipe to delete or use edit mode
5. **Empty State**: Shows a friendly message when no habits exist
6. **Visual Feedback**: Green checkmark when completed, gray circle when pending

## How to Use

1. Create a new iOS project in Xcode
2. Replace the default ContentView.swift and App file with the code above
3. Run the app on a simulator or device

This implementation is minimal but functional. For a production app, you might want to add features like:
- Streak tracking
- Calendar view of completions
- Habit categories
- Notifications
- Data backup
- More sophisticated data persistence (Core Data)

# Minimal iOS Habit Tracking App

Below is a minimal working version of a native iOS habit tracking application using SwiftUI. This app allows users to add habits, mark them as completed for the current day, and view their completion history.

```swift
import SwiftUI
import Foundation

// MARK: - Data Model
struct Habit: Identifiable, Codable {
    let id = UUID()
    let name: String
    var completionHistory: [Date: Bool] = [:] // Tracks completion by date

    // Check if habit is completed for today
    var isCompletedToday: Bool {
        let today = Calendar.current.startOfDay(for: Date())
        return completionHistory[today] == true
    }

    // Toggle completion for today
    mutating func toggleToday() {
        let today = Calendar.current.startOfDay(for: Date())
        completionHistory[today] = !isCompletedToday
    }
}

// MARK: - Data Manager
class HabitStore: ObservableObject {
    @Published var habits: [Habit] = []

    private let saveKey = "Habits"

    init() {
        // Load saved habits
        if let data = UserDefaults.standard.data(forKey: saveKey),
           let decoded = try? JSONDecoder().decode([Habit].self, from: data) {
            habits = decoded
        }
    }

    func addHabit(name: String) {
        guard !name.trimmingCharacters(in: .whitespaces).isEmpty else { return }
        habits.append(Habit(name: name))
        save()
    }

    func toggleHabit(_ habit: Habit) {
        if let index = habits.firstIndex(where: { $0.id == habit.id }) {
            habits[index].toggleToday()
            save()
        }
    }

    private func save() {
        if let data = try? JSONEncoder().encode(habits) {
            UserDefaults.standard.set(data, forKey: saveKey)
        }
    }
}

// MARK: - Add Habit View
struct AddHabitView: View {
    @Environment(\.presentationMode) var presentationMode
    @State private var habitName = ""
    @ObservedObject var store: HabitStore

    var body: some View {
        NavigationView {
            VStack {
                TextField("Enter habit name", text: $habitName)
                    .textFieldStyle(RoundedBorderTextFieldStyle())
                    .padding()

                Spacer()
            }
            .navigationBarTitle("New Habit", displayMode: .inline)
            .navigationBarItems(
                leading: Button("Cancel") {
                    presentationMode.wrappedValue.dismiss()
                },
                trailing: Button("Add") {
                    store.addHabit(name: habitName)
                    presentationMode.wrappedValue.dismiss()
                }.disabled(habitName.trimmingCharacters(in: .whitespaces).isEmpty)
            )
        }
    }
}

// MARK: - Habit List View
struct ContentView: View {
    @StateObject private var habitStore = HabitStore()
    @State private var showingAddHabit = false

    var body: some View {
        NavigationView {
            List {
                ForEach(habitStore.habits) { habit in
                    HStack {
                        VStack(alignment: .leading) {
                            Text(habit.name)
                                .font(.headline)

                            Text("Streak: \(calculateStreak(for: habit)) days")
                                .font(.caption)
                                .foregroundColor(.secondary)
                        }

                        Spacer()

                        Image(systemName: habit.isCompletedToday ? "checkmark.circle.fill" : "circle")
                            .foregroundColor(habit.isCompletedToday ? .green : .secondary)
                            .font(.title)
                            .onTapGesture {
                                habitStore.toggleHabit(habit)
                            }
                    }
                }
                .onDelete(perform: deleteHabits)
            }
            .navigationTitle("Habit Tracker")
            .toolbar {
                ToolbarItem(placement: .navigationBarLeading) {
                    EditButton()
                }

                ToolbarItem(placement: .navigationBarTrailing) {
                    Button(action: {
                        showingAddHabit = true
                    }) {
                        Image(systemName: "plus")
                    }
                }
            }
            .sheet(isPresented: $showingAddHabit) {
                AddHabitView(store: habitStore)
            }

            // Empty view when no habits
            if habitStore.habits.isEmpty {
                VStack {
                    Image(systemName: "checkmark.circle")
                        .font(.system(size: 60))
                        .foregroundColor(.gray)
                        .padding()

                    Text("No habits yet")
                        .font(.headline)
                        .foregroundColor(.secondary)

                    Text("Tap the + button to add your first habit")
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
            }
        }
    }

    private func calculateStreak(for habit: Habit) -> Int {
        var streak = 0
        var currentDate = Calendar.current.startOfDay(for: Date())

        // Go backwards day by day checking completion
        while let completed = habit.completionHistory[currentDate], completed {
            streak += 1
            guard let previousDay = Calendar.current.date(byAdding: .day, value: -1, to: currentDate) else {
                break
            }
            currentDate = Calendar.current.startOfDay(for: previousDay)
        }

        return streak
    }

    private func deleteHabits(offsets: IndexSet) {
        habitStore.habits.remove(atOffsets: offsets)
        habitStore.save()
    }
}

// MARK: - App Entry Point
@main
struct HabitTrackerApp: App {
    var body: some Scene {
        WindowGroup {
            ContentView()
        }
    }
}
```

## Key Features

1. **Habit Creation**: Add new habits with a name
2. **Daily Tracking**: Mark habits as complete for the current day with a simple tap
3. **Streak Calculation**: Shows current streak for each habit
4. **Data Persistence**: Saves habits and completion history using UserDefaults
5. **Edit/Delete**: Built-in swipe-to-delete functionality

## Implementation Notes

- Uses SwiftUI for modern, declarative UI
- Implements `ObservableObject` for state management
- Persists data with `UserDefaults` and `Codable`
- Responsive design that works on all iOS devices
- Clean, minimal interface following Apple's design guidelines

To use this code, create a new iOS project in Xcode and replace the default files with this implementation. The app requires iOS 14+ due to SwiftUI features used.

# Minimal iOS Habit Tracking App

Below is a minimal working version of a native iOS habit tracking application using SwiftUI. This code can be copied into a new iOS project in Xcode.

```swift
import SwiftUI

// Data model for a habit
struct Habit: Identifiable, Codable {
    let id = UUID()
    var name: String
    var completionCount: Int = 0
    var isActive: Bool = true
}

// Main app entry point
@main
struct HabitTrackerApp: App {
    var body: some Scene {
        WindowGroup {
            ContentView()
        }
    }
}

// Main view
struct ContentView: View {
    @StateObject private var habitManager = HabitManager()

    var body: some View {
        NavigationView {
            List {
                ForEach(habitManager.habits) { habit in
                    if habit.isActive {
                        HabitRow(habit: habit, habitManager: habitManager)
                    }
                }
                .onDelete(perform: deleteHabits)
            }
            .navigationTitle("Habits")
            .toolbar {
                Button("Add Habit") {
                    addNewHabit()
                }
            }
        }
    }

    func addNewHabit() {
        let newHabit = Habit(name: "New Habit")
        habitManager.addHabit(newHabit)
    }

    func deleteHabits(at offsets: IndexSet) {
        habitManager.deleteHabits(at: offsets)
    }
}

// Individual habit row view
struct HabitRow: View {
    let habit: Habit
    @StateObject var habitManager: HabitManager

    var body: some View {
        HStack {
            VStack(alignment: .leading) {
                Text(habit.name)
                    .font(.headline)
                Text("\(habit.completionCount) days completed")
                    .font(.caption)
                    .foregroundColor(.secondary)
            }

            Spacer()

            Button(action: {
                habitManager.completeHabit(habit)
            }) {
                Image(systemName: "plus.circle.fill")
                    .foregroundColor(.blue)
            }
        }
        .padding(.vertical, 4)
    }
}

// Manager to handle habit data
class HabitManager: ObservableObject {
    @Published var habits: [Habit] = [] {
        didSet {
            save()
        }
    }

    private let saveKey = "Habits"

    init() {
        if let data = UserDefaults.standard.data(forKey: saveKey),
           let decoded = try? JSONDecoder().decode([Habit].self, from: data) {
            habits = decoded
            return
        }
        habits = []
    }

    func addHabit(_ habit: Habit) {
        habits.append(habit)
    }

    func deleteHabits(at offsets: IndexSet) {
        habits.remove(atOffsets: offsets)
    }

    func completeHabit(_ habit: Habit) {
        if let index = habits.firstIndex(where: { $0.id == habit.id }) {
            habits[index].completionCount += 1
        }
    }

    private func save() {
        if let encoded = try? JSONEncoder().encode(habits) {
            UserDefaults.standard.set(encoded, forKey: saveKey)
        }
    }
}
```

