# Minimal iOS Habit Tracking App

Below is a minimal working version of a native iOS habit tracking application using SwiftUI. This code can be copied into an Xcode project (iOS 13+).

```swift
import SwiftUI

// Model for a habit
struct Habit: Identifiable, Codable {
    let id = UUID()
    var name: String
    var completedDates: [Date] = []
    var frequency: Frequency = .daily

    enum Frequency: String, Codable, CaseIterable {
        case daily = "Daily"
        case weekly = "Weekly"
        case monthly = "Monthly"
    }
}

// Main app entry point
@main
struct HabitTrackerApp: App {
    var body: some Scene {
        WindowGroup {
            ContentView()
                .environmentObject(HabitStore())
        }
    }
}

// Data store for habits
class HabitStore: ObservableObject {
    @Published var habits: [Habit] = [] {
        didSet {
            save()
        }
    }

    init() {
        load()
    }

    // Save habits to UserDefaults
    private func save() {
        if let encoded = try? JSONEncoder().encode(habits) {
            UserDefaults.standard.set(encoded, forKey: "Habits")
        }
    }

    // Load habits from UserDefaults
    private func load() {
        guard let data = UserDefaults.standard.data(forKey: "Habits"),
              let decoded = try? JSONDecoder().decode([Habit].self, from: data) else { return }
        habits = decoded
    }

    // Mark habit as completed for today
    func completeHabit(_ habit: Habit) {
        if let index = habits.firstIndex(where: { $0.id == habit.id }) {
            var updatedHabit = habits[index]
            // Check if already completed today
            let today = Calendar.current.startOfDay(for: Date())
            let alreadyCompleted = updatedHabit.completedDates.contains { 
                Calendar.current.startOfDay(for: $0) == today 
            }

            if !alreadyCompleted {
                updatedHabit.completedDates.append(Date())
                habits[index] = updatedHabit
            }
        }
    }

    // Check if habit was completed today
    func isCompletedToday(_ habit: Habit) -> Bool {
        let today = Calendar.current.startOfDay(for: Date())
        return habit.completedDates.contains { 
            Calendar.current.startOfDay(for: $0) == today 
        }
    }

    // Get completion count
    func completionCount(for habit: Habit) -> Int {
        return habit.completedDates.count
    }
}

// Main content view
struct ContentView: View {
    @EnvironmentObject var store: HabitStore
    @State private var showingAddHabit = false

    var body: some View {
        NavigationView {
            List {
                ForEach(store.habits) { habit in
                    HabitRow(habit: habit, isCompleted: store.isCompletedToday(habit))
                }
                .onDelete(perform: deleteHabits)
            }
            .navigationTitle("Habit Tracker")
            .toolbar {
                ToolbarItem(placement: .navigationBarTrailing) {
                    Button("Add") {
                        showingAddHabit = true
                    }
                }
            }
            .sheet(isPresented: $showingAddHabit) {
                AddHabitView()
            }

            Text("Select a habit or tap + to add one")
                .foregroundColor(.secondary)
        }
    }

    func deleteHabits(at offsets: IndexSet) {
        store.habits.remove(atOffsets: offsets)
    }
}

// Individual habit row
struct HabitRow: View {
    let habit: Habit
    let isCompleted: Bool
    @EnvironmentObject var store: HabitStore

    var body: some View {
        HStack {
            VStack(alignment: .leading) {
                Text(habit.name)
                    .font(.headline)
                Text("Completed \(store.completionCount(for: habit)) times")
                    .font(.caption)
                    .foregroundColor(.secondary)
            }

            Spacer()

            Button(isCompleted ? "Done ✓" : "Complete") {
                store.completeHabit(habit)
            }
            .buttonStyle(.bordered)
            .controlSize(.small)
            .buttonBorderShape(.capsule)
            .tint(isCompleted ? .green : .blue)
        }
        .padding(.vertical, 4)
    }
}

// Add new habit view
struct AddHabitView: View {
    @EnvironmentObject var store: HabitStore
    @Environment(\.dismiss) var dismiss

    @State private var name = ""
    @State private var frequency = Habit.Frequency.daily

    var body: some View {
        NavigationView {
            Form {
                Section("Habit Details") {
                    TextField("Habit name", text: $name)

                    Picker("Frequency", selection: $frequency) {
                        ForEach(Habit.Frequency.allCases) { frequency in
                            Text(frequency.rawValue).tag(frequency)
                        }
                    }
                }
            }
            .navigationTitle("New Habit")
            .toolbar {
                ToolbarItem(placement: .cancellationAction) {
                    Button("Cancel") {
                        dismiss()
                    }
                }

                ToolbarItem(placement: .confirmationAction) {
                    Button("Save") {
                        saveHabit()
                        dismiss()
                    }
                    .disabled(name.isEmpty)
                }
            }
        }
    }

    func saveHabit() {
        let habit = Habit(name: name, frequency: frequency)
        store.habits.append(habit)
    }
}

// Preview
struct ContentView_Previews: PreviewProvider {
    static var previews: some View {
        ContentView()
            .environmentObject(HabitStore())
    }
}
