# Minimal iOS Habit Tracking App

Here's a complete, minimal working version of a native iOS habit tracking application using SwiftUI. This code can be copied into a new Xcode project's main file (ContentView.swift or similar).

```swift
import SwiftUI

// Data model for a habit
struct Habit: Identifiable, Codable {
    let id = UUID()
    let name: String
    var completedDates: [String] = []

    // Check if habit is completed today
    var isCompletedToday: Bool {
        let today = formatDate(Date())
        return completedDates.contains(today)
    }

    // Format date as string (YYYY-MM-DD)
    private static func formatDate(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.dateFormat = "yyyy-MM-dd"
        return formatter.string(from: date)
    }
}

// Main app view
struct ContentView: View {
    @State private var habits: [Habit] = []
    @State private var showingAddHabit = false
    @State private var newHabitName = ""

    var body: some View {
        NavigationView {
            List {
                ForEach(habits) { habit in
                    HStack {
                        Text(habit.name)
                            .font(.headline)

                        Spacer()

                        // Completion button - toggles completion state
                        Button(habit.isCompletedToday ? "Done" : "Not Done") {
                            toggleHabitCompletion(habit: habit)
                        }
                        .buttonStyle(.bordered)
                        .foregroundColor(habit.isCompletedToday ? .green : .red)
                    }
                }
                .onDelete(perform: deleteHabits)
            }
            .navigationTitle("Habit Tracker")
            .toolbar {
                ToolbarItem(placement: .navigationBarLeading) {
                    EditButton()
                }

                ToolbarItem(placement: .navigationBarTrailing) {
                    Button("Add") {
                        showingAddHabit = true
                    }
                }
            }
            .sheet(isPresented: $showingAddHabit) {
                addHabitView
            }
            .onAppear(perform: loadHabits)
        }
    }

    // View for adding a new habit
    var addHabitView: some View {
        NavigationView {
            Form {
                TextField("Habit name", text: $newHabitName)

                Button("Add Habit") {
                    addHabit()
                }
            }
            .navigationTitle("New Habit")
            .toolbar {
                ToolbarItem(placement: .navigationBarTrailing) {
                    Button("Cancel") {
                        showingAddHabit = false
                        newHabitName = ""
                    }
                }
            }
        }
    }

    // Add a new habit
    func addHabit() {
        guard !newHabitName.trimmingCharacters(in: .whitespaces).isEmpty else { return }

        let habit = Habit(name: newHabitName)
        habits.append(habit)
        saveHabits()

        newHabitName = ""
        showingAddHabit = false
    }

    // Toggle habit completion status
    func toggleHabitCompletion(habit: Habit) {
        var updatedHabits = habits
        if let index = updatedHabits.firstIndex(where: { $0.id == habit.id }) {
            let today = Habit.formatDate(Date())
            if habit.isCompletedToday {
                // Remove today from completed dates
                updatedHabits[index].completedDates.removeAll { $0 == today }
            } else {
                // Add today to completed dates
                updatedHabits[index].completedDates.append(today)
            }
            habits = updatedHabits
            saveHabits()
        }
    }

    // Delete habits
    func deleteHabits(offsets: IndexSet) {
        habits.remove(atOffsets: offsets)
        saveHabits()
    }

    // Save habits to UserDefaults
    func saveHabits() {
        if let encoded = try? JSONEncoder().encode(habits) {
            UserDefaults.standard.set(encoded, forKey: "habits")
        }
    }

    // Load habits from UserDefaults
    func loadHabits() {
        if let data = UserDefaults.standard.data(forKey: "habits"),
           let decoded = try? JSONDecoder().decode([Habit].self, from: data) {
            habits = decoded
        }
    }
}

// App entry point
struct HabitTrackerApp: App {
    var body: some Scene {
        WindowGroup {
            ContentView()
        }
    }
}
```

## Key Features

1. **Create habits** - Add new habits with custom names
2. **Track completion** - Mark habits as done/not done for the current day
