import SwiftUI

// MARK: - Data Models
class Habit: Identifiable, ObservableObject, Codable {
    let id = UUID()
    @Published var name: String
    @Published var completionHistory: [Date: Bool] = [:] // Tracks completion by date

    init(name: String) {
        self.name = name
        // Initialize with today if not already set
        let today = Calendar.current.startOfDay(for: Date())
        self.completionHistory[today] = false
    }

    func toggleCompletion() {
        let today = Calendar.current.startOfDay(for: Date())
        completionHistory[today] = !(completionHistory[today] ?? false)
    }

    func isCompletedToday() -> Bool {
        let today = Calendar.current.startOfDay(for: Date())
        return completionHistory[today] ?? false
    }

    func streakCount() -> Int {
        let today = Calendar.current.startOfDay(for: Date())
        var count = 0
        var date = today

        while let completed = completionHistory[date], completed {
            count += 1
            guard let previousDay = Calendar.current.date(byAdding: .day, value: -1, to: date) else {
                break
            }
            date = Calendar.current.startOfDay(for: previousDay)
        }

        return count
    }
}

// MARK: - Persistence Manager
class HabitStore: ObservableObject {
    @Published var habits: [Habit] = []

    private static let saveKey = "Habits"

    init() {
        load()
    }

    func addHabit(name: String) {
        let habit = Habit(name: name)
        habits.append(habit)
        save()
    }

    func removeHabit(at offsets: IndexSet) {
        habits.remove(atOffsets: offsets)
        save()
    }

    private func save() {
        if let encoded = try? JSONEncoder().encode(habits) {
            UserDefaults.standard.set(encoded, forKey: HabitStore.saveKey)
        }
    }

    private func load() {
        guard 
            let data = UserDefaults.standard.data(forKey: HabitStore.saveKey),
            let decoded = try? JSONDecoder().decode([Habit].self, from: data)
        else { return }

        // Ensure today's date is in the completion history for each habit
        let today = Calendar.current.startOfDay(for: Date())
        for habit in decoded {
            if habit.completionHistory[today] == nil {
                habit.completionHistory[today] = false
            }
        }

        habits = decoded
    }
}

// MARK: - Views
struct ContentView: View {
    @EnvironmentObject var habitStore: HabitStore

    @State private var showingAddHabit = false
    @State private var newHabitName = ""

    var body: some View {
