// Habit.swift
import Foundation

struct Habit: Identifiable, Codable {
    let id = UUID()
    let name: String
    let description: String
    var completedDates: [String] // Stores dates as "YYYY-MM-DD"

    init(name: String, description: String) {
        self.name = name
        self.description = description
        self.completedDates = []
    }

    var currentStreak: Int {
        let today = Date()
        let calendar = Calendar.current

        // If no completions, streak is 0
        guard !completedDates.isEmpty else { return 0 }

        // Convert stored dates to Date objects
        let dateFormatter = DateFormatter()
        dateFormatter.dateFormat = "yyyy-MM-dd"

        var dates = completedDates.compactMap { dateFormatter.date(from: $0) }.sorted()

        // Check if today is already completed
        if let lastDate = dates.last,
           calendar.isDateInToday(lastDate) {
            // Today is already completed, so we count it
            // Now check consecutive days backwards
            return calculateConsecutiveDays(from: dates)
        } else {
            // Today is not completed, so we only count up to yesterday
            // Remove today if it was somehow added
            dates = dates.filter { !calendar.isDateInToday($0) }
            return calculateConsecutiveDays(from: dates)
        }
    }

    private func calculateConsecutiveDays(from dates: [Date]) -> Int {
        guard !dates.isEmpty else { return 0 }

        let calendar = Calendar.current
        var streak = 0
        var expectedDate = Date()

        // If the last completion wasn't today, move back one day
        if !calendar.isDateInToday(dates.last!) {
            expectedDate = calendar.date(byAdding: .day, value: -1, to: expectedDate)!
        }

        // Check backwards for consecutive days
        for date in dates.reversed() {
            if calendar.isDate(date, inSameDayAs: expectedDate) {
                streak += 1
                expectedDate = calendar.date(byAdding: .day, value: -1, to: expectedDate)!
            } else {
                break
            }
        }

        return streak
    }
}
