        let dateFormatter = DateFormatter()
        dateFormatter.dateFormat = "yyyy-MM-dd"
        let todayString = dateFormatter.string(from: today)

        // Create a new array with updated habit
        habits = habits.map { h in
            if h.id == habit.id {
                var updatedHabit = h
                if updatedHabit.completedDates.contains(todayString) {
                    // Remove today's completion
                    updatedHabit.completedDates = updatedHabit.completedDates.filter { $0 != todayString }
                } else {
                    // Add today's completion
                    updatedHabit.completedDates.append(todayString)
                }
                return updatedHabit
            }
            return h
        }
    }

    func deleteHabit(at offsets: IndexSet) {
        habits.remove(atOffsets: offsets)
    }

    // MARK: - Persistence

    private func saveHabits() {
        if let encoded = try? JSONEncoder().encode(habits) {
            userDefaults.set(encoded, forKey: habitsKey)
        }
    }

    private func loadHabits() {
        if let data = userDefaults.data(forKey: habitsKey),
           let decoded = try? JSONDecoder().decode([Habit].self, from: data) {
            habits = decoded
        }
    }
