```swift
// HabitManager.swift
import Foundation
import Combine

class HabitManager: ObservableObject {
    @Published var habits: [Habit] = [] {
        didSet {
            saveHabits()
        }
    }

    private let saveKey = "Habits"

    init() {
        loadHabits()
    }

    func addHabit(name: String, description: String) {
        let habit = Habit(name: name, description: description)
        habits.append(habit)
    }

    func toggleHabitCompletion(_ habit: Habit) {
        if let index = habits.firstIndex(where: { $0.id == habit.id }) {
            var updatedHabit = habit

            let calendar = Calendar.current
            let today = Date()

            // Check if already completed today
            let alreadyCompleted = habit.isCompletedToday()

            if alreadyCompleted {
                // Remove today's completion
                updatedHabit.completionDates = habit.completionDates.filter { 
                    !calendar.isDate($0, inSameDayAs: today) 
                }
            } else {
                // Add today's completion
                updatedHabit.completionDates.append(today)
            }

            habits[index] = updatedHabit
        }
    }

    private func saveHabits() {
        if let encoded = try? JSONEncoder().encode(habits) {
            UserDefaults.standard.set(encoded, forKey: saveKey)
        }
    }

    private func loadHabits() {
        guard let data = UserDefaults.standard.data(forKey: saveKey),
              let decoded = try? JSONDecoder().decode([Habit].self, from: data) else {
            habits = []
            return
        }
        habits = decoded
    }
}
