```swift
// Habit.swift
import Foundation

struct Habit: Identifiable, Codable {
    let id = UUID()
    let name: String
    let description: String
    var completedDates: [Date]

    init(name: String, description: String) {
        self.name = name
        self.description = description
        self.completedDates = []
    }

    var completionStreak: Int {
        let calendar = Calendar.current
        let today = Date()
        let yesterday = calendar.date(byAdding: .day, value: -1, to: today)!

        // If completed today, add to streak
        let isCompletedToday = completedDates.contains { 
            calendar.isDate($0, inSameDayAs: today) 
        }

        // Calculate current streak
        var streak = 0
        var currentDate = today

        while true {
            let isCompleted = completedDates.contains { 
                calendar.isDate($0, inSameDayAs: currentDate) 
            }

            if isCompleted {
                streak += 1
                currentDate = calendar.date(byAdding: .day, value: -1, to: currentDate)!
            } else {
                // Break if today is not completed or if yesterday wasn't completed (gap in streak)
                if currentDate == today || !completedDates.contains { 
                    calendar.isDate($0, inSameDayAs: yesterday) 
                } || streak == 0 {
                    break
                }
            }
        }

        return streak
    }
}
