    private func getRecentDays() -> [(Date, Bool)] {
        let calendar = Calendar.current
        var results: [(Date, Bool)] = []
        let today = Date()

        // Show last 7 days
        for dayOffset in stride(from: 6, through: 0, by: -1) {
            let date = calendar.date(byAdding: .day, value: -dayOffset, to: today)!
            let completed = habit.completedDates.contains { 
                calendar.isDate($0, inSameDayAs: date) 
            }
            results.append((date, completed))
        }

        return results
    }

    private func getDayString(from date: Date) -> String {
        let formatter = DateFormatter()
        formatter.dateFormat = "EEEE"

        let today = Date()
        let calendar = Calendar.current

        if calendar.isDate(date, inSameDayAs: today) {
            return "Today"
        } else if calendar.isDate(date, inSameDayAs: calendar.date(byAdding: .day, value: -1, to: today)!) {
            return "Yesterday"
        } else {
            return formatter.string(from: date)
        }
    }
