```swift
import SwiftUI

// Model for a habit
struct Habit: Identifiable, Codable {
    let id = UUID()
    let name: String
    var completedDates: [Date] = []

    var isCompletedToday: Bool {
        let calendar = Calendar.current
        let today = Date()
        return completedDates.contains { date in
            calendar.isDate(date, inSameDayAs: today)
        }
    }
}

// Main app entry point
@main
struct HabitTrackerApp: App {
    var body: some Scene {
        WindowGroup {
            ContentView()
                .environmentObject(HabitStore())
        }
    }
}

// Data store for habits
class HabitStore: ObservableObject {
    @Published var habits: [Habit] = [] {
        didSet {
            save()
        }
    }

    private let saveKey = "Habits"

    init() {
        load()
    }

    func add(_ habit: Habit) {
        habits.append(habit)
    }

    func toggleHabit(_ habit: Habit) {
        if let index = habits.firstIndex(where: { $0.id == habit.id }) {
            let calendar = Calendar.current
            let today = Date()

            if habit.isCompletedToday {
                // Remove today's completion
                habits[index].completedDates = habits[index].completedDates.filter { 
                    !calendar.isDate($0, inSameDayAs: today) 
                }
            } else {
                // Add today's completion
                habits[index].completedDates.append(today)
            }
        }
    }

    private func save() {
        if let encoded = try? JSONEncoder().encode(habits) {
            UserDefaults.standard.set(encoded, forKey: saveKey)
        }
    }

    private func load() {
        guard let data = UserDefaults.standard.data(forKey: saveKey),
              let decoded = try? JSONDecoder().decode([Habit].self, from: data) else { return }
        habits = decoded
    }
}

// Main content view
struct ContentView: View {
    @EnvironmentObject var store: HabitStore
    @State private var showingAddHabit = false
    @State private var newHabitName = ""

    var body: some View {
        NavigationView {
            List {
                ForEach(store.habits) { habit in
                    HStack {
                        Text(habit.name)
                            .font(.headline)

                        Spacer()

                        Text("\(habit.completedDates.count) completed")
                            .foregroundColor(.secondary)
                            .font(.caption)

                        Button(habit.isCompletedToday ? "Done" : "Mark Complete") {
                            store.toggleHabit(habit)
                        }
                        .buttonStyle(.bordered)
                        .controlSize(.small)
                        .tint(habit.isCompletedToday ? .green : .blue)
                    }
                }
                .onDelete(perform: deleteHabits)
            }
            .navigationTitle("Habit Tracker")
            .toolbar {
                ToolbarItem(placement: .navigationBarTrailing) {
                    Button("Add") {
                        showingAddHabit = true
                    }
                }

                ToolbarItem(placement: .navigationBarLeading) {
                    EditButton()
                }
            }
            .sheet(isPresented: $showingAddHabit) {
                VStack {
                    TextField("Habit name", text: $newHabitName)
                        .textFieldStyle(.roundedBorder)
                        .padding()

                    Button("Add Habit") {
                        guard !newHabitName.trimmingCharacters(in: .whitespaces).isEmpty else { return }
                        let habit = Habit(name: newHabitName)
                        store.add(habit)
                        newHabitName = ""
                        showingAddHabit = false
                    }
                    .buttonStyle(.bordered)
                    .padding()
                    .disabled(newHabitName.trimmingCharacters(in: .whitespaces).isEmpty)
                }
                .padding()
                .navigationTitle("New Habit")
                .navigationBarTitleDisplayMode(.inline)
            }
            .onAppear {
                UITableView.appearance().backgroundColor = .systemGroupedBackground
            }
        }
    }

    func deleteHabits(at offsets: IndexSet) {
        store.habits.remove(atOffsets: offsets)
    }
}
