### 3. `Source/MyPhysicsPlugin/Public/MyPhysicsComponent.h`

```cpp
#pragma once

#include "CoreMinimal.h"
#include "Components/ActorComponent.h"
#include "MyPhysicsComponent.generated.h"

UCLASS(ClassGroup=(Custom), meta=(BlueprintSpawnableComponent))
class MYPHYSICSPLUGIN_API UMyPhysicsComponent : public UActorComponent
{
    GENERATED_BODY()

public:	
    // Sets default values for this component's properties
    UMyPhysicsComponent();

protected:
    // Called when the game starts
    virtual void BeginPlay() override;

public:	
    // Called every frame
    virtual void TickComponent(float DeltaTime, ELevelTick TickType, FActorComponentTickFunction* ThisTickFunction) override;

    // Force magnitude (editable in Blueprint)
    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Physics")
    float UpwardForce;

private:
    // Cache the owning PrimitiveComponent for physics interaction
    class UPrimitiveComponent* AttachedBody;
};
