### 4. `Source/MyPhysicsPlugin/Private/MyPhysicsComponent.cpp`

```cpp
#include "MyPhysicsComponent.h"
#include "GameFramework/Actor.h"
#include "Components/PrimitiveComponent.h"

UMyPhysicsComponent::UMyPhysicsComponent()
{
    // Set this component to be ticked every frame
    PrimaryComponentTick.bCanEverTick = true;
    UpwardForce = 500.0f; // Default upward force
}

void UMyPhysicsComponent::BeginPlay()
{
    Super::BeginPlay();

    // Try to get the root component as a physics body
    AActor* Owner = GetOwner();
    if (Owner)
    {
        AttachedBody = Cast<UPrimitiveComponent>(Owner->GetRootComponent());
        if (!AttachedBody || !AttachedBody->IsSimulatingPhysics())
        {
            UE_LOG(LogTemp, Warning, TEXT("UMyPhysicsComponent: No physics-enabled body found on owner."));
        }
    }
}

void UMyPhysicsComponent::TickComponent(float DeltaTime, ELevelTick TickType, FActorComponentTickFunction* ThisTickFunction)
{
    Super::TickComponent(DeltaTime, TickType, ThisTickFunction);

    // Apply upward force if valid physics body
    if (AttachedBody && AttachedBody->IsSimulatingPhysics())
    {
        AttachedBody->AddForce(FVector::UpVector * UpwardForce);
    }
}
```

