// CustomPhysicsComponent.cpp
#include "CustomPhysicsComponent.h"
#include "GameFramework/Actor.h"
#include "Engine/World.h"

UCustomPhysicsComponent::UCustomPhysicsComponent()
{
    PrimaryComponentTick.bCanEverTick = true;
    Gravity = -980.0f; // cm/s² (Unreal uses cm)
    Velocity = FVector::ZeroVector;
}

void UCustomPhysicsComponent::BeginPlay()
{
    Super::BeginPlay();
    // Optionally initialize physics state
}

void UCustomPhysicsComponent::TickComponent(float DeltaTime, ELevelTick TickType, FActorComponentTickFunction* ThisTickFunction)
{
    Super::TickComponent(DeltaTime, TickType, ThisTickFunction);

    AActor* Owner = GetOwner();
    if (!Owner) return;

    // Apply gravity
    Velocity.Z += Gravity * DeltaTime;

    // Move actor
    FVector DeltaLocation = Velocity * DeltaTime;
    Owner->AddActorWorldOffset(DeltaLocation, true); // sweep for collisions
}
```

