#include "MyPhysicsPluginModule.h"
#include "Engine/World.h"
#include "GameFramework/Actor.h"
#include "Components/StaticMeshComponent.h"
#include "TimerManager.h"

IMPLEMENT_MODULE(FMyPhysicsPluginModule, MyPhysicsPlugin)

void FMyPhysicsPluginModule::StartupModule()
{
    // Register a delegate to run every frame
    FWorldDelegates::OnStartPhysicsTick.AddLambda([](float DeltaSeconds)
    {
        for (TObjectIterator<AActor> ActorIt; ActorIt; ++ActorIt)
        {
            AActor* Actor = *ActorIt;
            UWorld* World = Actor->GetWorld();
            if (!World || !World->IsGameWorld()) continue;

            // Find StaticMeshComponent with physics enabled
            UStaticMeshComponent* MeshComp = Actor->FindComponentByClass<UStaticMeshComponent>();
            if (MeshComp && MeshComp->IsSimulatingPhysics())
            {
                // Apply small upward force (like buoyancy)
                MeshComp->AddForce(FVector(0, 0, 50.0f));
            }
        }
    });
}

void FMyPhysicsPluginModule::ShutdownModule()
{
    // Clean up if needed
}
