### 📄 4. `Source/MyPhysicsPlugin/Private/MyPhysicsPlugin.cpp`

```cpp
#include "MyPhysicsPlugin.h"
#include "Engine/World.h"
#include "GameFramework/Actor.h"
#include "PhysicsEngine/PhysicsSettings.h"
#include "PhysicsEngine/BodyInstance.h"
#include "EngineUtils.h"
#include "Tickable.h"

// Called when the module is loaded
void FMyPhysicsPlugin::StartupModule()
{
    // Register to tick after physics
    TickHandle = FTSTicker::GetCoreTicker().AddTicker(
        FTickerDelegate::CreateStatic(&FMyPhysicsPlugin::PhysicsTick),
        0.0f // Tick every frame
    );
}

// Called when the module is unloaded
void FMyPhysicsPlugin::ShutdownModule()
{
    if (FTSTicker::GetCoreTicker().IsValid() && TickHandle.IsValid())
    {
        FTSTicker::GetCoreTicker().RemoveTicker(TickHandle);
        TickHandle.Reset();
    }
}

// Physics tick: Apply force to all physics-enabled actors
void FMyPhysicsPlugin::PhysicsTick(float DeltaTime)
{
    // Iterate through all worlds (e.g. PIE, Game, Editor)
    for (TObjectIterator<UWorld> It; It; ++It)
    {
        UWorld* World = *It;
        if (!World || !World->HasBegunPlay()) continue;

        // Iterate through all actors in the world
        for (TActorIterator<AActor> ActorItr(World); ActorItr; ++ActorItr)
        {
            AActor* Actor = *ActorItr;
            if (!Actor->IsRootComponentCollisionEnabled()) continue;

            UPrimitiveComponent* RootComp = Actor->GetRootPrimitiveComponent();
            if (!RootComp || !RootComp->IsSimulatingPhysics()) continue;

            // Apply small upward force (e.g., anti-gravity effect)
            RootComp->AddForce(FVector(0, 0, 50.0f), NAME_None, true);
        }
    }
}
```

