    WaterLevel = 0.0f;
}

void UBuoyancyComponent::BeginPlay()
{
    Super::BeginPlay();
}

void UBuoyancyComponent::TickComponent(float DeltaTime, ELevelTick TickType, FActorComponentTickFunction* ThisTickFunction)
{
    Super::TickComponent(DeltaTime, TickType, ThisTickFunction);

    AActor* Owner = GetOwner();
    if (!Owner) return;

    UPrimitiveComponent* PrimComp = Cast<UPrimitiveComponent>(Owner->GetRootComponent());
    if (!PrimComp || !PrimComp->IsSimulatingPhysics()) return;

    float Z = Owner->GetActorLocation().Z;
    float Depth = WaterLevel - Z;

    if (Depth > 0.0f)
    {
        // Apply upward buoyancy force proportional to submersion depth
        FVector BuoyancyForce = FVector::UpVector * BuoyancyStrength * Depth;
        PrimComp->AddForce(BuoyancyForce);
    }
}
```

