```rust
use hyper::service::service_fn;
use hyper::{Body, Method, Request, Response, Result, StatusCode};
use hyper_util::rt::TokioIo;
use std::convert::Infallible;
use std::net::SocketAddr;
use tokio::net::TcpListener;
use tracing::{info, error};

// Simple handler function
async fn handle_request(req: Request<Body>) -> Result<Response<Body>, Infallible> {
    // Match request method and path
    let response = match (req.method(), req.uri().path()) {
        (&Method::GET, "/") => Response::new(Body::from("Hello, High-Performance World!")),

        (&Method::GET, "/health") => Response::new(Body::from("OK")),

        (&Method::GET, "/echo") => {
            let body_bytes = hyper::body::to_bytes(req.into_body()).await.unwrap_or_default();
            Response::new(Body::from(body_bytes))
        }

        _ => {
            let mut not_found = Response::new(Body::from("Not Found"));
            *not_found.status_mut() = StatusCode::NOT_FOUND;
            not_found
        }
    };

    Ok(response)
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
    // Initialize logging
    tracing_subscriber::fmt::init();

    let addr: SocketAddr = ([0, 0, 0, 0], 3000).into();

    let listener = TcpListener::bind(addr).await?;
    info!("Listening on http://{}", addr);

    loop {
        let (stream, _) = listener.accept().await?;

        // Use Tokio to spawn a new task for each connection
        tokio::task::spawn(async move {
            // Convert TCP stream to something hyper can use
            let io = TokioIo::new(stream);

            // Serve the connection with hyper
            if let Err(err) = hyper::server::conn::http1::Builder::new()
                .serve_connection(io, service_fn(handle_request))
                .await
            {
                error!("Error serving connection: {:?}", err);
            }
        });
    }
}
```

