use tokio::net::{TcpListener, TcpStream};
use tokio::io::{AsyncReadExt, AsyncWriteExt};
use std::net::SocketAddr;

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let addr = "0.0.0.0:8080";
    let listener = TcpListener::bind(addr).await?;
    println!("🚀 High-performance server listening on http://{}", addr);

    loop {
        let (stream, client_addr) = listener.accept().await?;
        tokio::spawn(async move {
            if let Err(e) = handle_connection(stream, client_addr).await {
                eprintln!("❌ Error handling connection from {}: {}", client_addr, e);
            }
        });
    }
}

async fn handle_connection(mut stream: TcpStream, addr: SocketAddr) -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
    let mut buffer = [0; 1024];
    let n = stream.read(&mut buffer).await?;

    // Optional: Parse request method/path if needed
    let request_line = String::from_utf8_lossy(&buffer[..n]);
    if !request_line.is_empty() {
        // Log first line of request (optional, may impact performance at scale)
        // println!("📩 Request from {}: {}", addr, request_line.lines().next().unwrap_or("Unknown"));
    }

    // Build a minimal HTTP response
    let response = "HTTP/1.1 200 OK\r\n\
                    Content-Length: 13\r\n\
                    Content-Type: text/plain\r\n\
                    Connection: keep-alive\r\n\
                    \r\n\
                    Hello, World!";

    stream.write_all(response.as_bytes()).await?;
    stream.flush().await?;

    // For production: consider keep-alive and pipelining
    Ok(())
}
```

