```rust
use hyper::service::{make_service_fn, service_fn};
use hyper::{Body, Request, Response, Server, StatusCode};
use std::convert::Infallible;
use std::net::SocketAddr;
use std::sync::atomic::{AtomicU64, Ordering};
use std::sync::Arc;

// Shared state to count requests
type SharedCounter = Arc<AtomicU64>;

async fn handle_request(_req: Request<Body>, counter: SharedCounter) -> Result<Response<Body>, Infallible> {
    // Increment request counter
    let count = counter.fetch_add(1, Ordering::Relaxed);

    // Respond with a simple JSON message
    let response_body = format!(r#"{{"message": "Hello from high-performance server!", "request_id": {}}}"#, count);

    Ok(Response::new(Body::from(response_body)))
}

#[tokio::main]
async fn main() {
    // Shared atomic counter for tracking requests
    let counter = Arc::new(AtomicU64::new(1));

    // Create a service factory that clones the counter for each connection
    let make_svc = make_service_fn(move |_conn| {
        let counter = counter.clone();
        async move {
            Ok::<_, Infallible>(service_fn(move |req| {
                handle_request(req, counter.clone())
            }))
        }
    });

    // Bind to address
    let addr = SocketAddr::from(([0, 0, 0, 0], 3000));

    // Create server
    let server = Server::bind(&addr).serve(make_svc);

    println!("🚀 High-performance server listening on http://{}", addr);

    // Run the server
    if let Err(e) = server.await {
        eprintln!("❌ Server error: {}", e);
    }
}
```

