package main

import (
    "context"
    "log"
    "net/http"
    "os"
    "os/signal"
    "sync"
    "syscall"
    "time"
)

// Handler for the root endpoint
func helloHandler(w http.ResponseWriter, r *http.Request) {
    // Simple JSON response
    w.Header().Set("Content-Type", "application/json")
    w.WriteHeader(http.StatusOK)
    w.Write([]byte(`{"message": "Hello, World!", "timestamp": "` + time.Now().Format(time.RFC3339) + `"}`))
}

// Health check endpoint
func healthHandler(w http.ResponseWriter, r *http.Request) {
    w.Header().Set("Content-Type", "application/json")
    w.WriteHeader(http.StatusOK)
    w.Write([]byte(`{"status": "healthy", "timestamp": "` + time.Now().Format(time.RFC3339) + `"}`))
}

func main() {
    // Create a wait group to manage graceful shutdown
    var wg sync.WaitGroup

    // Create a new HTTP server with optimized settings
    server := &http.Server{
        Addr:         ":8080",
        ReadTimeout:  5 * time.Second,
        WriteTimeout: 10 * time.Second,
        IdleTimeout:  120 * time.Second,
        Handler: http.TimeoutHandler(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
            // Add request ID for tracing (simplified)
            w.Header().Set("X-Request-ID", time.Now().Format("20060102150405.999999999"))

            // Route requests
            switch r.URL.Path {
            case "/":
                helloHandler(w, r)
            case "/health":
                healthHandler(w, r)
            default:
                http.NotFound(w, r)
            }
        }), 30*time.Second, `{"error": "request timeout"}`),
    }

    // Set up graceful shutdown
    stop := make(chan os.Signal, 1)
    signal.Notify(stop, syscall.SIGINT, syscall.SIGTERM)

    // Start the server in a goroutine
    go func() {
        log.Println("Starting server on :8080")
        if err := server.ListenAndServe(); err != nil && err != http.ErrServerClosed {
            log.Printf("Server error: %v", err)
        }
    }()

    // Wait for interrupt signal
    <-stop
    log.Println("Shutting down server...")

    // Create a deadline for shutdown
    ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
    defer cancel()

    // Shutdown the server gracefully
    if err := server.Shutdown(ctx); err != nil {
        log.Printf("Server forced to shutdown: %v", err)
    }

    log.Println("Server stopped")
    wg.Wait()
}
```

