Here's a minimal high-performance web server using **Rust with Tokio**, designed for handling a large number of concurrent requests efficiently:

```rust
// main.rs
use tokio::net::TcpListener;
use tokio::io::{AsyncReadExt, AsyncWriteExt};

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let addr = "0.0.0.0:8080";
    let listener = TcpListener::bind(addr).await?;
    println!("Server listening on {}", addr);

    loop {
        let (mut socket, _) = listener.accept().await?;

        // Spawn a new task for each connection (non-blocking)
        tokio::spawn(async move {
            let mut buf = [0; 1024];

            // Read request
            let n = match socket.read(&mut buf).await {
                Ok(n) if n == 0 => return,
                Ok(n) => n,
                Err(_) => return,
            };

            // Parse HTTP method and path (simplified)
            let request = String::from_utf8_lossy(&buf[..n]);
            let mut lines = request.lines();
            let first_line = lines.next().unwrap_or("");
            let parts: Vec<&str> = first_line.split_whitespace().collect();
            let path = if parts.len() > 1 { parts[1] } else { "/" };

            // Generate response based on path
            let (status, body) = match path {
                "/" => ("200 OK", "Hello, World!"),
                "/health" => ("200 OK", "OK"),
                _ => ("404 Not Found", "Not Found"),
            };

            let response = format!(
                "HTTP/1.1 {}\r\nContent-Length: {}\r\nContent-Type: text/plain\r\nConnection: close\r\n\r\n{}",
                status,
                body.len(),
                body
            );

            // Write response
            let _ = socket.write_all(response.as_bytes()).await;
        });
    }
}
```

